import java.util.*;

class FileSystem {
    class Node {
        boolean isFile = false;
        String content = "";
        Map<String, Node> children = new TreeMap<>();
    }

    Node root;

    public FileSystem() {
        root = new Node();
    }

    public List<String> ls(String path) {
        Node node = root;
        List<String> path_parts = splitPath(path);

        for (String part : path_parts) {
            node = node.children.get(part);
        }

        if (node.isFile) {
            return Collections.singletonList(path_parts.get(path_parts.size() - 1));
        } else {
            return new ArrayList<>(node.children.keySet());
        }
    }

    public void mkdir(String path) {
        Node node = root;
        List<String> path_parts = splitPath(path);

        for (String part : path_parts) {
            node.children.putIfAbsent(part, new Node());
            node = node.children.get(part);
        }
    }

    public void addContentToFile(String filePath, String content) {
        Node node = root;
        List<String> path_parts = splitPath(filePath);

        for (String part : path_parts) {
            node.children.putIfAbsent(part, new Node());
            node = node.children.get(part);
        }

        node.isFile = true;
        node.content += content;
    }

    public String readContentFromFile(String filePath) {
        Node node = root;
        List<String> path_parts = splitPath(filePath);

        for (String part : path_parts) {
            node = node.children.get(part);
        }

        return node.content;
    }

    private List<String> splitPath(String path) {
        List<String> parts = new ArrayList<>();
        String[] tokens = path.split("/");
        for (String token : tokens) {
            if (!token.isEmpty()) {
                parts.add(token);
            }
        }
        return parts;
    }
}
